mapper.select:
SELECT T.PARENTID , count(1) count FROM T_LCDP_RESOURCE T WHERE DELETEFLAG ='0' AND PARENTID in
#{id}
GROUP BY PARENTID

SELECT R.ID, R.RESOURCENAME, R.PARENTID, R.CATEGORYID, R.MODULEID, R.EFFECTVERSION, /* 生效版本 */ R.CREATEDBYID, /* 创建人编码 */ R.CHECKOUTUSERID, /* 检出人编码 */ R.CHECKOUTTIME /* 检出人时间 */ FROM T_LCDP_RESOURCE R WHERE R.RESOURCECATEGORY IN ('java', 'mapper', 'view', 'js') AND R.DELETEFLAG = '0' AND R.CHECKOUTUSERID IS NOT NULL
AND R.CATEGORYID IN
${categoryId}

SELECT R.ID, R.RESOURCENAME, R.PARENTID, R.CATEGORYID, R.MODULEID, R.EFFECTVERSION, /* 生效版本 */ R.CREATEDBYID, /* 创建人编码 */ S.SCRIPTSTATUS ERRORSTATUS /* 编译失败，脚本状态 */ FROM T_LCDP_RESOURCE R, T_LCDP_ERROR_SCRIPT S WHERE R.ID = S.SERVERSCRIPTID AND R.RESOURCECATEGORY IN ('java', 'mapper', 'view', 'js') AND R.DELETEFLAG = '0'
AND R.CATEGORYID IN
${categoryId}

SELECT DISTINCT R.MODULEID ID, R.CATEGORYID PARENTID FROM T_LCDP_RESOURCE R WHERE R.RESOURCECATEGORY IN ('java', 'mapper', 'view', 'js') AND R.DELETEFLAG = '0' AND R.CHECKOUTUSERID IS NULL
AND R.CATEGORYID IN
${categoryId}

SELECT R.* FROM T_LCDP_RESOURCE R WHERE R.RESOURCECATEGORY IN ('java', 'mapper', 'view', 'js') AND R.DELETEFLAG = '0' AND R.EFFECTVERSION > 0 AND R.CHECKOUTUSERID IS NULL
AND R.MODULEID IN
${moduleId}

SELECT ${columns}
SELECT R.*
FROM T_LCDP_RESOURCE R WHERE R.RESOURCECATEGORY IN ('java', 'mapper', 'view', 'js') AND R.DELETEFLAG = '0' AND R.CHECKOUTUSERID = #{userId} AND EXISTS (SELECT 1 FROM T_LCDP_RS_CHECKOUT_RECORD C WHERE R.ID = C.RESOURCEID AND C.CHECKOUTUSERID = #{userId})

SELECT DISTINCT R.MODULEID ID, R.CATEGORYID PARENTID FROM T_LCDP_RESOURCE R WHERE R.RESOURCECATEGORY IN ('java', 'mapper', 'view', 'js') AND R.EFFECTVERSION > 0
AND R.CATEGORYID IN
${categoryId}
